import React from "react";
import Navbar from "./components/Navbar";
import Categories from "./components/Categories";
import Banner from "./components/Banner";
import Products from "./components/Products";

function App() {
  return (
    <div>
      {/* Navbar */}
      <Navbar />

      {/* Categories */}
      <Categories />

      {/* Banner Slider */}
      <Banner />

      {/* Product Section */}
      <Products />
    </div>
  );
}

export default App;
